# incident_lifecycle.py — structured incident state machine
from dataclasses import dataclass, field
from datetime import datetime, timezone
from enum import Enum
from typing import Optional

class IncidentState(Enum):
    DETECTED    = 'detected'
    ACKNOWLEDGED = 'acknowledged'
    INVESTIGATING = 'investigating'
    MITIGATING  = 'mitigating'
    RESOLVED    = 'resolved'
    POSTMORTEM  = 'postmortem'

@dataclass
class IncidentTimeline:
    incident_id: str
    severity: str   # 'P1', 'P2', 'P3', 'P4'
    detected_at: datetime
    acknowledged_at: Optional[datetime] = None
    mitigated_at: Optional[datetime]   = None
    resolved_at: Optional[datetime]    = None
    state: IncidentState = IncidentState.DETECTED
    notes: list[str] = field(default_factory=list)

    @property
    def time_to_acknowledge_minutes(self) -> Optional[float]:
        if not self.acknowledged_at:
            return None
        delta = self.acknowledged_at - self.detected_at
        return delta.total_seconds() / 60

    @property
    def time_to_mitigate_minutes(self) -> Optional[float]:
        if not self.mitigated_at:
            return None
        delta = self.mitigated_at - self.detected_at
        return delta.total_seconds() / 60

    def sla_breached(self) -> bool:
        ack_sla = {'P1': 15, 'P2': 30, 'P3': 120, 'P4': None}
        limit = ack_sla.get(self.severity)
        if limit and self.time_to_acknowledge_minutes:
            return self.time_to_acknowledge_minutes > limit
        return False

    def requires_postmortem(self) -> bool:
        """P1 incidents and P2 incidents lasting >4h require a post-mortem."""
        if self.severity == 'P1':
            return True
        if self.severity == 'P2' and self.time_to_mitigate_minutes:
            return self.time_to_mitigate_minutes > 240
        return False

    def add_note(self, note: str) -> None:
        now = datetime.now(timezone.utc).strftime('%H:%M UTC')
        self.notes.append(f'[{now}] {note}')

# status_page_updater.py — posts incident status to external status page
import os, requests
from severity_classifier import Severity

STATUS_API_URL   = os.environ['STATUS_PAGE_API_URL']
STATUS_API_TOKEN = os.environ['STATUS_PAGE_API_TOKEN']

# Only post customer-facing updates for P1 and prolonged P2
CUSTOMER_FACING_SEVERITIES = {Severity.P1}

COMPONENT_MAP = {
    'availability': 'AI API',
    'latency_p95':  'AI API',
    'eval_quality': 'AI Response Quality',
    'safety':       'AI Content Safety',
}

def post_status_update(
    severity: Severity,
    slo_id: str,
    message: str,
    component_status: str = 'degraded_performance',
) -> bool:
    if severity not in CUSTOMER_FACING_SEVERITIES:
        return False  # P2/P3/P4 do not get external status updates

    component = COMPONENT_MAP.get(slo_id, 'AI Services')
    payload = {
        'incident': {
            'name': f'Investigating issue with {component}',
            'status': 'investigating',
            'body': message,
            'components': {
                component: component_status,
            },
        }
    }
    resp = requests.post(
        f'{STATUS_API_URL}/incidents',
        json=payload,
        headers={'Authorization': f'OAuth {STATUS_API_TOKEN}'},
        timeout=10,
    )
    return resp.status_code == 201

def resolve_status_incident(incident_id: str, resolution_message: str) -> bool:
    payload = {
        'incident': {
            'status': 'resolved',
            'body': resolution_message,
        }
    }
    resp = requests.patch(
        f'{STATUS_API_URL}/incidents/{incident_id}',
        json=payload,
        headers={'Authorization': f'OAuth {STATUS_API_TOKEN}'},
        timeout=10,
    )
    return resp.status_code == 200
